<?php
namespace App\Services\Security;use App\Models\{SecurityIncident,SecurityIncidentCorrectiveAction,User};use Illuminate\Validation\ValidationException;
class SecurityCorrectiveActionVerificationService{public function requestVerification(SecurityIncidentCorrectiveAction $x,User $a,string $note):SecurityIncidentCorrectiveAction{if($x->status!=='completed')throw ValidationException::withMessages(['action'=>'Corrective action must be completed before verification.']);return $this->update($x,$a,['verification_status'=>'pending','verification_note'=>$note],'verification_requested',$note);}public function verify(SecurityIncidentCorrectiveAction $x,User $a,string $note,string $evidence):SecurityIncidentCorrectiveAction{if(!$a->can('admin.security.corrective_actions.verify'))throw ValidationException::withMessages(['permission'=>'Corrective action verification permission is required.']);if($x->completed_by_id===$a->id&&!$a->can('admin.security.incidents.override_closure_blockers'))throw ValidationException::withMessages(['verification'=>'Completer cannot verify the same corrective action.']);if(trim($note)===''||trim($evidence)==='')throw ValidationException::withMessages(['verification'=>'Verification note and evidence summary are required.']);return $this->update($x,$a,['verification_status'=>'verified','verification_note'=>$note,'verification_evidence_summary'=>$evidence,'verified_by_id'=>$a->id,'verified_at'=>now()],'corrective_action_verified',$note);}public function rejectVerification(SecurityIncidentCorrectiveAction $x,User $a,string $reason):SecurityIncidentCorrectiveAction{return $this->update($x,$a,['verification_status'=>'rejected','verification_rejected_by_id'=>$a->id,'verification_rejected_at'=>now(),'verification_rejection_reason'=>$reason],'corrective_action_verification_rejected',$reason);}public function getVerificationReadiness(SecurityIncident $i):array{$pending=$i->correctiveActions()->where('verification_required',true)->where('verification_status','!=','verified')->count();return ['ready'=>$pending===0,'pending'=>$pending];}private function update($x,$a,$d,$t,$note){$x->update($d);SecurityIncident::find($x->security_incident_id)->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$note,'created_at'=>now()]);return $x->refresh();}}
